const express = require('express');
const bodyParser = require('body-parser');
const { Configuration, OpenAIApi } = require('openai');

const app = express();
app.use(bodyParser.json());

// Set up OpenAI API configuration
const configuration = new Configuration({
  apiKey: process.env.OPENAI_API_KEY,
});
const openai = new OpenAIApi(configuration);

// Middleware to prevent LLM jailbreak
function preventJailbreak(req, res, next) {
  const userInput = req.body.description;
  if (userInput.includes('jailbreak') || userInput.includes('exit')) {
    return res.status(403).json({ error: 'Access denied' });
  }
  next();
}

app.post('/generate-code', preventJailbreak, async (req, res) => {
  const { description } = req.body;

  try {
    const response = await openai.createCompletion({
      model: 'text-davinci-003',
      prompt: `Generate code based on the following natural language description:\n${description}`,
      max_tokens: 150,
    });

    const generatedCode = response.data.choices[0].text.trim();
    res.json({ generatedCode });
  } catch (error) {
    res.status(500).json({ error: 'Failed to generate code' });
  }
});

app.listen(3000, () => {
  console.log('Server is running on port 3000');
});